parameters.jsCode:
const output = $json.output;

let parsed;

try {
  parsed = typeof output === 'string' ? JSON.parse(output) : output;
} catch (error) {
  parsed = {
    resposta_cliente: output || "Desculpe, nÃ£o consegui processar sua mensagem.",
    intencao: "outro",
    precisa_humano: false,
    nome: "",
    telefone: "",
    cidade: "",
    produto_interesse: "",
    quantidade: "",
    material_aplicacao: "",
    descricao: "",
    resumo: ""
  };
}

return [
  {
    json: {
      ...parsed,
      telefone: parsed.telefone || $('Padronizar mensagem do cliente').item.json.telefone,
      tipo_mensagem: $('Padronizar mensagem do cliente').item.json.tipo_mensagem,
      mensagem_usuario: $('Padronizar mensagem do cliente').item.json.mensagem_usuario
    }
  }
];

